// ══════════════════════════════════════════════
//  IMPORTS
//  useState  → manejo de estado local en componentes
//  useEffect → efectos secundarios (fetch al montar)
// ══════════════════════════════════════════════
import { useState, useEffect } from 'react';
import './style.css';
import Nav from './components/Nav';
impo

// ══════════════════════════════════════════════
//  COMPONENTES REUTILIZABLES (moldes)
// ══════════════════════════════════════════════



// Ítem de la carta (pizza / aperitivo / postre)
function MenuItem({ item }) {
  return (
    <div className="menu-item">
      <div className="menu-item-info">
        <h4>{item.nombre}</h4>
        <p>{item.descripcion}</p>
      </div>
      <span className="menu-item-precio">{item.precio}</span>
    </div>
  );
}

// Fila de horario en la sección de contacto
function HoraFila({ fila }) {
  return (
    <div className="hora-fila">
      <span>{fila.dias}</span>
      <span>{fila.hora}</span>
    </div>
  );
}

// Dato de contacto: ícono + etiqueta + valor
function DatoContacto({ icono, etiqueta, valor }) {
  return (
    <div className="dato">
      <div className="dato-icono">{icono}</div>
      <div className="dato-texto">
        <strong>{etiqueta}</strong>
        <span>{valor}</span>
      </div>
    </div>
  );
}


// ══════════════════════════════════════════════
//  FORMULARIO DE RESERVA
//  Maneja sus propios estados internos (campos,
//  errores, éxito). No depende de props externas.
// ══════════════════════════════════════════════
function FormularioReserva() {

  // ── Estados para cada campo controlado ──
  const [nombre,    setNombre]    = useState('');
  const [email,     setEmail]     = useState('');
  const [fechaHora, setFechaHora] = useState('');
  const [personas,  setPersonas]  = useState('');

  // ── Estado de errores por campo ──
  // Cada clave contiene el mensaje de error, o '' si no hay error
  const [errores, setErrores] = useState({
    nombre:    '',
    email:     '',
    fechaHora: '',
    personas:  '',
  });

  // ── Estado de envío exitoso ──
  // Cuando es true se oculta el formulario y aparece el mensaje de confirmación
  const [enviado, setEnviado] = useState(false);


  // ── Función de validación ──
  // Recibe todos los campos y devuelve un objeto con los mensajes de error
  const validar = (campos) => {
    const erroresNuevos = { nombre: '', email: '', fechaHora: '', personas: '' };

    // Ningún campo puede estar vacío
    if (!campos.nombre.trim()) {
      erroresNuevos.nombre = 'El nombre es obligatorio.';
    }

    if (!campos.email.trim()) {
      erroresNuevos.email = 'El email es obligatorio.';
    } else if (!campos.email.includes('@') || !campos.email.includes('.')) {
      // El email debe tener '@' y al menos un punto
      erroresNuevos.email = 'Ingresá un email válido (debe contener @ y un punto).';
    }

    if (!campos.fechaHora) {
      erroresNuevos.fechaHora = 'La fecha y hora son obligatorias.';
    } else {
      // La fecha seleccionada no puede ser anterior al momento actual
      const fechaIngresada = new Date(campos.fechaHora);
      const ahora          = new Date();
      if (fechaIngresada <= ahora) {
        erroresNuevos.fechaHora = 'La fecha debe ser posterior a hoy.';
      }
    }

    if (!campos.personas) {
      erroresNuevos.personas = 'La cantidad de personas es obligatoria.';
    } else if (Number(campos.personas) <= 0) {
      // La cantidad debe ser mayor a 0
      erroresNuevos.personas = 'La cantidad de personas debe ser mayor a 0.';
    }

    return erroresNuevos;
  };


  // ── Manejador del evento submit ──
  const handleSubmit = (e) => {
    // Evita que el navegador recargue la página al enviar el formulario
    e.preventDefault();

    const erroresEncontrados = validar({ nombre, email, fechaHora, personas });
    setErrores(erroresEncontrados);

    // Si ningún campo tiene mensaje de error, el formulario es válido
    const hayErrores = Object.values(erroresEncontrados).some(msg => msg !== '');
    if (!hayErrores) {
      setEnviado(true);
    }
  };


  // ── Pantalla de éxito ──
  // Reemplaza al formulario cuando enviado === true
  if (enviado) {
    return (
      <div className="reserva-exito">
        <span className="reserva-exito-icono">🍕</span>
        <h3>¡Reserva confirmada!</h3>
        <p>
          Gracias, <strong>{nombre}</strong>. Te esperamos el{' '}
          <strong>
            {new Date(fechaHora).toLocaleString('es-AR', {
              dateStyle: 'long',
              timeStyle: 'short',
            })}
          </strong>{' '}
          con tu mesa para{' '}
          <strong>{personas} {Number(personas) === 1 ? 'persona' : 'personas'}</strong>.
        </p>
        <p className="reserva-exito-sub">
          Te enviaremos la confirmación a <em>{email}</em>.
        </p>
      </div>
    );
  }

  // ── Formulario ──
  return (
    <form className="reserva-form" onSubmit={handleSubmit} noValidate>

      <h3 className="reserva-titulo">Reservá tu mesa</h3>

      {/* Campo: Nombre */}
      <div className="campo-grupo">
        <label className="campo-label" htmlFor="res-nombre">Nombre completo</label>
        <input
          id="res-nombre"
          type="text"
          className={`campo-input${errores.nombre ? ' campo-input--error' : ''}`}
          placeholder="Ej: María García"
          value={nombre}
          onChange={(e) => setNombre(e.target.value)}
        />
        {errores.nombre && <span className="campo-error">{errores.nombre}</span>}
      </div>

      {/* Campo: Email */}
      <div className="campo-grupo">
        <label className="campo-label" htmlFor="res-email">Email</label>
        <input
          id="res-email"
          type="email"
          className={`campo-input${errores.email ? ' campo-input--error' : ''}`}
          placeholder="Ej: maria@email.com"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
        {errores.email && <span className="campo-error">{errores.email}</span>}
      </div>

      {/* Campo: Fecha y hora — solo permite fechas futuras */}
      <div className="campo-grupo">
        <label className="campo-label" htmlFor="res-fecha">Fecha y hora</label>
        <input
          id="res-fecha"
          type="datetime-local"
          className={`campo-input${errores.fechaHora ? ' campo-input--error' : ''}`}
          value={fechaHora}
          onChange={(e) => setFechaHora(e.target.value)}
        />
        {errores.fechaHora && <span className="campo-error">{errores.fechaHora}</span>}
      </div>

      {/* Campo: Cantidad de personas */}
      <div className="campo-grupo">
        <label className="campo-label" htmlFor="res-personas">Cantidad de personas</label>
        <input
          id="res-personas"
          type="number"
          min="1"
          className={`campo-input${errores.personas ? ' campo-input--error' : ''}`}
          placeholder="Ej: 2"
          value={personas}
          onChange={(e) => setPersonas(e.target.value)}
        />
        {errores.personas && <span className="campo-error">{errores.personas}</span>}
      </div>

      <button type="submit" className="btn-carta reserva-btn">
        Confirmar reserva
      </button>

    </form>
  );
}


// ══════════════════════════════════════════════
//  SECCIONES DE LA PÁGINA
// ══════════════════════════════════════════════

// Sección hero con las tres pizzas destacadas
function Hero({ pizzasDestacadas }) {
  return (
    <section id="inicio">
      <p className="hero-label">Pizzería Artesanal · Desde 1994</p>
      <h1 className="hero-title">La <span>Piazza</span></h1>
      <p className="hero-sub">
        Masa madre, ingredientes frescos y el horno de leña que lleva generaciones encendido.
      </p>

      <div className="pizza-grid">
        {pizzasDestacadas.map(pizza => (
          <PizzaCard key={pizza.id} pizza={pizza} />
        ))}
      </div>

      <div className="cta-wrap">
        <a href="#carta" className="btn-carta">Ver carta completa</a>
      </div>
    </section>
  );
}

// Sección carta con sistema de pestañas accesible
function Carta({ carta }) {
  // tabActiva controla qué pestaña se muestra
  const [tabActiva, setTabActiva] = useState('pizzas');

  const tabs = [
    { key: 'pizzas',     label: 'Pizzas'     },
    { key: 'aperitivos', label: 'Aperitivos' },
    { key: 'postres',    label: 'Postres'    },
  ];

  return (
    <>
      <div className="divisor">
        <span></span><em>· Nuestra Carta ·</em><span></span>
      </div>

      <section id="carta">
        <h2 className="seccion-titulo">Lo que sale del horno</h2>
        <p className="seccion-sub">Pizzas · Aperitivos · Postres</p>

        {/*
          Tabs accesibles:
          role="tablist"  → agrupa las pestañas para lectores de pantalla
          role="tab"      → cada botón es una pestaña
          aria-selected   → indica cuál está activa (true/false dinámico)
        */}
        <div className="tabs" role="tablist">
          {tabs.map(tab => (
            <button
              key={tab.key}
              role="tab"
              aria-selected={tabActiva === tab.key}
              className={`tab-btn${tabActiva === tab.key ? ' activo' : ''}`}
              onClick={() => setTabActiva(tab.key)}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Grilla de ítems de la tab activa */}
        <div className="menu-grid">
          {carta[tabActiva].map(item => (
            <MenuItem key={item.id} item={item} />
          ))}
        </div>
      </section>
    </>
  );
}

// Sección de contacto: horarios + formulario + datos
function Contacto({ contacto }) {
  return (
    <>
      <div className="divisor">
        <span></span><em>· Encontranos ·</em><span></span>
      </div>

      <section id="contacto">
        <div className="contacto-inner contacto-inner--tres-col">

          {/* Columna 1: horarios de atención */}
          <div className="contacto-texto">
            <h2>Vení a visitarnos</h2>
            <p>
              Estamos en el corazón del barrio, esperándote con el horno encendido
              y una buena botella de vino.
            </p>
            <div className="horarios">
              <h3>Horarios de atención</h3>
              {contacto.horarios.map((fila, i) => (
                <HoraFila key={i} fila={fila} />
              ))}
            </div>
          </div>

          {/* Columna 2: formulario de reserva */}
          <FormularioReserva />

          {/* Columna 3: datos de contacto */}
          <div className="contacto-datos">
            <DatoContacto icono="📍" etiqueta="Dirección"  valor={contacto.direccion}  />
            <DatoContacto icono="📞" etiqueta="Teléfono"   valor={contacto.telefono}   />
            <DatoContacto icono="💬" etiqueta="WhatsApp"   valor={contacto.whatsapp}   />
            <DatoContacto icono="✉️" etiqueta="Email"      valor={contacto.email}      />
            <DatoContacto icono="📷" etiqueta="Instagram"  valor={contacto.instagram}  />
          </div>

        </div>
      </section>
    </>
  );
}

// Pie de página
function Footer() {
  return (
    <footer>
      © 2026 <em>La Piazza</em> · Todos los derechos reservados
    </footer>
  );
}


// ══════════════════════════════════════════════
//  APP RAÍZ
//  Responsabilidad: cargar data.json de forma
//  asíncrona y distribuir los datos como props.
//
//  Estados:
//    datos    → objeto con pizzasDestacadas, carta y contacto
//    cargando → true mientras el fetch no terminó
//    error    → mensaje de error si el fetch falló
// ══════════════════════════════════════════════
export default function App() {
  const [datos,    setDatos]    = useState(null);
  const [cargando, setCargando] = useState(true);
  const [error,    setError]    = useState(null);

  // useEffect con [] → se ejecuta una sola vez al montar el componente
  useEffect(() => {
    const cargarDatos = async () => {
      try {
        // fetch trae el archivo estático desde la carpeta public
        const respuesta = await fetch('/data.json');

        // Si la respuesta HTTP no es 2xx, lanzamos un error explícito
        if (!respuesta.ok) {
          throw new Error(`Error ${respuesta.status}: ${respuesta.statusText}`);
        }

        // await convierte la respuesta a objeto JS
        const json = await respuesta.json();
        setDatos(json);

      } catch (err) {
        setError(err.message);
      } finally {
        // Siempre desactivamos la pantalla de carga, haya error o no
        setCargando(false);
      }
    };

    cargarDatos();
  }, []);


  // ── Pantalla de carga ──
  // Usa clase CSS, no estilos inline: la presentación queda en style.css
  if (cargando) {
    return (
      <div className="estado-carga">
        <span>🍕</span>
        Calentando los hornos...
      </div>
    );
  }

  // ── Pantalla de error ──
  if (error) {
    return (
      <div className="estado-error">
        <span>⚠️</span>
        <strong>Algo salió mal</strong>
        <p>{error}</p>
      </div>
    );
  }

  // ── Render principal ──
  return (
    <>
      {/*
        <nav> queda fuera de <main> porque es un landmark de navegación global.
        <main> agrupa el contenido central: hero, carta y contacto.
        <footer> queda fuera de <main> porque es un landmark de pie de página.
      */}
      <Nav />
      <main>
        <Hero     pizzasDestacadas={datos.pizzasDestacadas} />
        <Carta    carta={datos.carta} />
        <Contacto contacto={datos.contacto} />
      </main>
      <Footer />
    </>
  );
}
